oldWay:
/* The overflow-hidden wrapper trick */
.image-wrapper {
  width: 160px;
  height: 160px;
  overflow: hidden;
  position: relative;
}
.image-wrapper img {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100%;
  height: auto;
}

startingCSS:
.gallery {
  display: flex;
  gap: 0.75rem;
  padding: 1rem;
  background: #1e293b;
  border-radius: 10px;
}

.photo {
  width: 160px;
  height: 160px;
  border-radius: 8px;
  display: block;
  /* Images are distorted — fix with object-fit */
}

alternatives.css:
.photo {
  width: 160px;
  height: 160px;
  object-fit: contain;
  background: #0f172a; /* makes the letterbox area visible */
